mapper.insert:
/* IncidentLogMapper.insertIncidentLog - 사고접수 이력 insert */
INSERT INTO Incident_log (
report_no
, report_date
, intake_method_cd
, status_cd
, site_cd
, lat
, lng

    , addr


    , cell_phone

, rpt_img_path
, rpt_img_name
, captured_at
, accuracy_m
, captured_ts
, ocr_read_km
) values (
#{reportNo}
, NOW()
, #{intakeMethodCd}
, #{statusCd}
, #{siteCd}
, #{lat}
, #{lng}

    , #{addr}


    , HEX(AES_ENCRYPT(#{cellPhone}, 'RSOS'))

, #{rptImgPath}
, #{rptImgName}
, #{capturedAt}
, #{accuracyM,jdbcType=INTEGER}
, #{capturedTs,jdbcType=BIGINT}
, #{ocrReadKm}
)
